<?php/** * AquaLuxe Helper Functions * * This file contains helper functions used throughout the theme. * * @package AquaLuxe */// Exit if accessed directlyif (!defined('ABSPATH')) {    exit;}/** * Get theme option * * @param string $option_name * @param mixed $default * @return mixed */function aqualuxe_get_option($option_name, $default = '') {    $options = get_theme_mod('aqualuxe_options', []);    return isset($options[$option_name]) ? $options[$option_name] : $default;}/** * Get theme color * * @param string $color_name * @param string $default * @return string */function aqualuxe_get_color($color_name, $default = '') {    $colors = [        'primary' => '#0072B5',        'primary-light' => '#0090E1',        'primary-dark' => '#005A8E',        'secondary' => '#00B2A9',        'secondary-light' => '#00D6CC',        'secondary-dark' => '#008E87',        'accent' => '#F8C630',        'accent-light' => '#FFDA6A',        'accent-dark' => '#D9A400',        'luxe' => '#2C3E50',        'luxe-light' => '#3E5871',        'luxe-dark' => '#1A2530',    ];        // Get color from theme mod    $theme_color = get_theme_mod('aqualuxe_color_' . str_replace('-', '_', $color_name), '');        // Return theme mod color if set    if (!empty($theme_color)) {        return $theme_color;    }        // Return default color if exists    if (isset($colors[$color_name])) {        return $colors[$color_name];    }        // Return provided default    return $default;}/** * Get image URL by ID * * @param int $attachment_id * @param string $size * @return string */function aqualuxe_get_image_url($attachment_id, $size = 'full') {    if (empty($attachment_id)) {        return '';    }        $image = wp_get_attachment_image_src($attachment_id, $size);        return $image ? $image[0] : '';}/** * Get image alt text by ID * * @param int $attachment_id * @return string */function aqualuxe_get_image_alt($attachment_id) {    if (empty($attachment_id)) {        return '';    }        $alt = get_post_meta($attachment_id, '_wp_attachment_image_alt', true);        return $alt ? $alt : '';}/** * Get SVG icon * * @param string $icon * @param array $args * @return string */function aqualuxe_get_icon($icon, $args = []) {    // Default args    $defaults = [        'class' => '',        'size' => 24,        'fill' => 'currentColor',        'stroke' => 'currentColor',        'stroke-width' => 2,        'aria-hidden' => 'true',    ];        // Parse args    $args = wp_parse_args($args, $defaults);        // Extract args    $class = $args['class'] ? ' ' . $args['class'] : '';    $size = $args['size'];    $fill = $args['fill'];    $stroke = $args['stroke'];    $stroke_width = $args['stroke-width'];    $aria_hidden = $args['aria-hidden'] ? 'true' : 'false';        // Base attributes    $svg_attr = [        'class' => 'icon icon-' . $icon . $class,        'width' => $size,        'height' => $size,        'aria-hidden' => $aria_hidden,        'role' => 'img',        'focusable' => 'false',    ];        // Build attributes string    $svg_attr_str = '';    foreach ($svg_attr as $key => $value) {        $svg_attr_str .= $key . '="' . esc_attr($value) . '" ';    }        // Get icon path    $icon_path = AQUALUXE_DIR . '/assets/dist/images/icons/' . $icon . '.svg';        // Return empty string if icon doesn't exist    if (!file_exists($icon_path)) {        return '';    }        // Get icon content    $icon_content = file_get_contents($icon_path);        // Replace SVG attributes    $icon_content = preg_replace('/<svg[^>]*>/', '<svg ' . $svg_attr_str . '>', $icon_content);        // Replace fill and stroke attributes    $icon_content = str_replace('fill="currentColor"', 'fill="' . $fill . '"', $icon_content);    $icon_content = str_replace('stroke="currentColor"', 'stroke="' . $stroke . '"', $icon_content);    $icon_content = str_replace('stroke-width="2"', 'stroke-width="' . $stroke_width . '"', $icon_content);        return $icon_content;}/** * Get social links * * @return array */function aqualuxe_get_social_links() {    $social_links = [        'facebook' => [            'label' => __('Facebook', 'aqualuxe'),            'url' => aqualuxe_get_option('social_facebook', ''),            'icon' => 'facebook',        ],        'twitter' => [            'label' => __('Twitter', 'aqualuxe'),            'url' => aqualuxe_get_option('social_twitter', ''),            'icon' => 'twitter',        ],        'instagram' => [            'label' => __('Instagram', 'aqualuxe'),            'url' => aqualuxe_get_option('social_instagram', ''),            'icon' => 'instagram',        ],        'youtube' => [            'label' => __('YouTube', 'aqualuxe'),            'url' => aqualuxe_get_option('social_youtube', ''),            'icon' => 'youtube',        ],        'linkedin' => [            'label' => __('LinkedIn', 'aqualuxe'),            'url' => aqualuxe_get_option('social_linkedin', ''),            'icon' => 'linkedin',        ],        'pinterest' => [            'label' => __('Pinterest', 'aqualuxe'),            'url' => aqualuxe_get_option('social_pinterest', ''),            'icon' => 'pinterest',        ],    ];        // Filter out empty URLs    $social_links = array_filter($social_links, function($link) {        return !empty($link['url']);    });        return apply_filters('aqualuxe_social_links', $social_links);}/** * Get contact information * * @return array */function aqualuxe_get_contact_info() {    $contact_info = [        'address' => aqualuxe_get_option('contact_address', ''),        'phone' => aqualuxe_get_option('contact_phone', ''),        'email' => aqualuxe_get_option('contact_email', ''),        'hours' => aqualuxe_get_option('contact_hours', ''),    ];        return apply_filters('aqualuxe_contact_info', $contact_info);}/** * Get page title * * @return string */function aqualuxe_get_page_title() {    if (is_home()) {        if (get_option('page_for_posts', true)) {            return get_the_title(get_option('page_for_posts', true));        } else {            return __('Latest Posts', 'aqualuxe');        }    } elseif (is_archive()) {        if (is_post_type_archive()) {            return post_type_archive_title('', false);        } elseif (is_tax() || is_category() || is_tag()) {            return single_term_title('', false);        } elseif (is_author()) {            return get_the_author();        } elseif (is_date()) {            if (is_year()) {                return get_the_date(_x('Y', 'yearly archives date format', 'aqualuxe'));            } elseif (is_month()) {                return get_the_date(_x('F Y', 'monthly archives date format', 'aqualuxe'));            } elseif (is_day()) {                return get_the_date();            }        }        return __('Archives', 'aqualuxe');    } elseif (is_search()) {        return sprintf(__('Search Results for: %s', 'aqualuxe'), get_search_query());    } elseif (is_404()) {        return __('Page Not Found', 'aqualuxe');    } else {        return get_the_title();    }}/** * Get breadcrumbs * * @return array */function aqualuxe_get_breadcrumbs() {    $breadcrumbs = [];        // Home    $breadcrumbs[] = [        'label' => __('Home', 'aqualuxe'),        'url' => home_url('/'),    ];        if (is_home()) {        // Blog        if (get_option('page_for_posts', true)) {            $breadcrumbs[] = [                'label' => get_the_title(get_option('page_for_posts', true)),                'url' => '',            ];        } else {            $breadcrumbs[] = [                'label' => __('Blog', 'aqualuxe'),                'url' => '',            ];        }    } elseif (is_singular('post')) {        // Blog        if (get_option('page_for_posts', true)) {            $breadcrumbs[] = [                'label' => get_the_title(get_option('page_for_posts', true)),                'url' => get_permalink(get_option('page_for_posts', true)),            ];        } else {            $breadcrumbs[] = [                'label' => __('Blog', 'aqualuxe'),                'url' => '',            ];        }                // Categories        $categories = get_the_category();        if (!empty($categories)) {            $category = $categories[0];            $breadcrumbs[] = [                'label' => $category->name,                'url' => get_category_link($category->term_id),            ];        }                // Post        $breadcrumbs[] = [            'label' => get_the_title(),            'url' => '',        ];    } elseif (is_singular('page')) {        // Ancestors        $ancestors = get_post_ancestors(get_the_ID());        if (!empty($ancestors)) {            $ancestors = array_reverse($ancestors);            foreach ($ancestors as $ancestor) {                $breadcrumbs[] = [                    'label' => get_the_title($ancestor),                    'url' => get_permalink($ancestor),                ];            }        }                // Page        $breadcrumbs[] = [            'label' => get_the_title(),            'url' => '',        ];    } elseif (is_archive()) {        if (is_post_type_archive()) {            $breadcrumbs[] = [                'label' => post_type_archive_title('', false),                'url' => '',            ];        } elseif (is_tax() || is_category() || is_tag()) {            $term = get_queried_object();                        // Check if term has ancestors            if (is_taxonomy_hierarchical($term->taxonomy) && $term->parent) {                $ancestors = get_ancestors($term->term_id, $term->taxonomy);                $ancestors = array_reverse($ancestors);                foreach ($ancestors as $ancestor_id) {                    $ancestor = get_term($ancestor_id, $term->taxonomy);                    $breadcrumbs[] = [                        'label' => $ancestor->name,                        'url' => get_term_link($ancestor),                    ];                }            }                        $breadcrumbs[] = [                'label' => $term->name,                'url' => '',            ];        } elseif (is_author()) {            $breadcrumbs[] = [                'label' => get_the_author(),                'url' => '',            ];        } elseif (is_date()) {            if (is_year()) {                $breadcrumbs[] = [                    'label' => get_the_date(_x('Y', 'yearly archives date format', 'aqualuxe')),                    'url' => '',                ];            } elseif (is_month()) {                $breadcrumbs[] = [                    'label' => get_the_date(_x('F Y', 'monthly archives date format', 'aqualuxe')),                    'url' => '',                ];            } elseif (is_day()) {                $breadcrumbs[] = [                    'label' => get_the_date(),                    'url' => '',                ];            }        } else {            $breadcrumbs[] = [                'label' => __('Archives', 'aqualuxe'),                'url' => '',            ];        }    } elseif (is_search()) {        $breadcrumbs[] = [            'label' => sprintf(__('Search Results for: %s', 'aqualuxe'), get_search_query()),            'url' => '',        ];    } elseif (is_404()) {        $breadcrumbs[] = [            'label' => __('Page Not Found', 'aqualuxe'),            'url' => '',        ];    }        return apply_filters('aqualuxe_breadcrumbs', $breadcrumbs);}/** * Get post excerpt * * @param int $post_id * @param int $length * @param string $more * @return string */function aqualuxe_get_excerpt($post_id = null, $length = 55, $more = '&hellip;') {    $post = get_post($post_id);        if (empty($post)) {        return '';    }        if (has_excerpt($post->ID)) {        $excerpt = $post->post_excerpt;    } else {        $excerpt = $post->post_content;    }        $excerpt = strip_shortcodes($excerpt);    $excerpt = excerpt_remove_blocks($excerpt);    $excerpt = strip_tags($excerpt);    $excerpt = str_replace('&nbsp;', ' ', $excerpt);    $excerpt = trim($excerpt);        if (strlen($excerpt) > $length) {        $excerpt = substr($excerpt, 0, $length);        $excerpt = substr($excerpt, 0, strrpos($excerpt, ' '));        $excerpt .= $more;    }        return $excerpt;}/** * Get related posts * * @param int $post_id * @param int $count * @return array */function aqualuxe_get_related_posts($post_id = null, $count = 3) {    $post = get_post($post_id);        if (empty($post)) {        return [];    }        // Get post categories    $categories = get_the_category($post->ID);    $category_ids = [];        if (!empty($categories)) {        foreach ($categories as $category) {            $category_ids[] = $category->term_id;        }    }        // Get post tags    $tags = get_the_tags($post->ID);    $tag_ids = [];        if (!empty($tags)) {        foreach ($tags as $tag) {            $tag_ids[] = $tag->term_id;        }    }        // Query args    $args = [        'post_type' => 'post',        'post_status' => 'publish',        'posts_per_page' => $count,        'post__not_in' => [$post->ID],        'orderby' => 'rand',    ];        // Add tax query if we have categories or tags    if (!empty($category_ids) || !empty($tag_ids)) {        $args['tax_query'] = ['relation' => 'OR'];                if (!empty($category_ids)) {            $args['tax_query'][] = [                'taxonomy' => 'category',                'field' => 'term_id',                'terms' => $category_ids,            ];        }                if (!empty($tag_ids)) {            $args['tax_query'][] = [                'taxonomy' => 'post_tag',                'field' => 'term_id',                'terms' => $tag_ids,            ];        }    }        $related_posts = get_posts($args);        return $related_posts;}/** * Get post thumbnail with fallback * * @param int $post_id * @param string $size * @param array $attr * @return string */function aqualuxe_get_post_thumbnail($post_id = null, $size = 'post-thumbnail', $attr = []) {    $post = get_post($post_id);        if (empty($post)) {        return '';    }        if (has_post_thumbnail($post->ID)) {        return get_the_post_thumbnail($post->ID, $size, $attr);    }        // Get default image from theme options    $default_image_id = aqualuxe_get_option('default_featured_image', '');        if (!empty($default_image_id)) {        return wp_get_attachment_image($default_image_id, $size, false, $attr);    }        // Return empty string if no default image    return '';}/** * Get post author info * * @param int $post_id * @return array */function aqualuxe_get_post_author($post_id = null) {    $post = get_post($post_id);        if (empty($post)) {        return [];    }        $author_id = $post->post_author;        $author = [        'id' => $author_id,        'name' => get_the_author_meta('display_name', $author_id),        'url' => get_author_posts_url($author_id),        'avatar' => get_avatar_url($author_id, ['size' => 96]),        'description' => get_the_author_meta('description', $author_id),    ];        return $author;}/** * Get post date * * @param int $post_id * @param string $format * @return string */function aqualuxe_get_post_date($post_id = null, $format = '') {    $post = get_post($post_id);        if (empty($post)) {        return '';    }        if (empty($format)) {        $format = get_option('date_format');    }        return get_the_date($format, $post->ID);}/** * Get post modified date * * @param int $post_id * @param string $format * @return string */function aqualuxe_get_post_modified_date($post_id = null, $format = '') {    $post = get_post($post_id);        if (empty($post)) {        return '';    }        if (empty($format)) {        $format = get_option('date_format');    }        return get_the_modified_date($format, $post->ID);}/** * Get post categories * * @param int $post_id * @return array */function aqualuxe_get_post_categories($post_id = null) {    $post = get_post($post_id);        if (empty($post)) {        return [];    }        $categories = get_the_category($post->ID);        if (empty($categories)) {        return [];    }        $result = [];        foreach ($categories as $category) {        $result[] = [            'id' => $category->term_id,            'name' => $category->name,            'slug' => $category->slug,            'url' => get_category_link($category->term_id),        ];    }        return $result;}/** * Get post tags * * @param int $post_id * @return array */function aqualuxe_get_post_tags($post_id = null) {    $post = get_post($post_id);        if (empty($post)) {        return [];    }        $tags = get_the_tags($post->ID);        if (empty($tags)) {        return [];    }        $result = [];        foreach ($tags as $tag) {        $result[] = [            'id' => $tag->term_id,            'name' => $tag->name,            'slug' => $tag->slug,            'url' => get_tag_link($tag->term_id),        ];    }        return $result;}/** * Get post comments count * * @param int $post_id * @return int */function aqualuxe_get_post_comments_count($post_id = null) {    $post = get_post($post_id);        if (empty($post)) {        return 0;    }        return get_comments_number($post->ID);}/** * Get pagination * * @param array $args * @return string */function aqualuxe_get_pagination($args = []) {    global $wp_query;        $defaults = [        'total' => $wp_query->max_num_pages,        'current' => max(1, get_query_var('paged')),        'prev_text' => '&larr; ' . __('Previous', 'aqualuxe'),        'next_text' => __('Next', 'aqualuxe') . ' &rarr;',        'type' => 'array',        'end_size' => 3,        'mid_size' => 3,    ];        $args = wp_parse_args($args, $defaults);        $pagination = paginate_links($args);        if (empty($pagination)) {        return '';    }        $output = '<nav class="pagination" aria-label="' . esc_attr__('Pagination', 'aqualuxe') . '">';    $output .= '<ul class="pagination-list">';        foreach ($pagination as $page_link) {        $output .= '<li class="pagination-item">' . $page_link . '</li>';    }        $output .= '</ul>';    $output .= '</nav>';        return $output;}/** * Get post navigation * * @param int $post_id * @return array */function aqualuxe_get_post_navigation($post_id = null) {    $post = get_post($post_id);        if (empty($post)) {        return [];    }        $prev_post = get_previous_post();    $next_post = get_next_post();        $navigation = [        'prev' => [],        'next' => [],    ];        if (!empty($prev_post)) {        $navigation['prev'] = [            'id' => $prev_post->ID,            'title' => get_the_title($prev_post->ID),            'url' => get_permalink($prev_post->ID),            'thumbnail' => aqualuxe_get_post_thumbnail($prev_post->ID, 'thumbnail'),        ];    }        if (!empty($next_post)) {        $navigation['next'] = [            'id' => $next_post->ID,            'title' => get_the_title($next_post->ID),            'url' => get_permalink($next_post->ID),            'thumbnail' => aqualuxe_get_post_thumbnail($next_post->ID, 'thumbnail'),        ];    }        return $navigation;}/** * Get share links * * @param int $post_id * @return array */function aqualuxe_get_share_links($post_id = null) {    $post = get_post($post_id);        if (empty($post)) {        return [];    }        $permalink = get_permalink($post->ID);    $title = get_the_title($post->ID);    $excerpt = aqualuxe_get_excerpt($post->ID, 140);        $share_links = [        'facebook' => [            'label' => __('Share on Facebook', 'aqualuxe'),            'url' => 'https://www.facebook.com/sharer/sharer.php?u=' . urlencode($permalink),            'icon' => 'facebook',        ],        'twitter' => [            'label' => __('Share on Twitter', 'aqualuxe'),            'url' => 'https://twitter.com/intent/tweet?url=' . urlencode($permalink) . '&text=' . urlencode($title),            'icon' => 'twitter',        ],        'linkedin' => [            'label' => __('Share on LinkedIn', 'aqualuxe'),            'url' => 'https://www.linkedin.com/shareArticle?mini=true&url=' . urlencode($permalink) . '&title=' . urlencode($title) . '&summary=' . urlencode($excerpt),            'icon' => 'linkedin',        ],        'pinterest' => [            'label' => __('Share on Pinterest', 'aqualuxe'),            'url' => 'https://pinterest.com/pin/create/button/?url=' . urlencode($permalink) . '&description=' . urlencode($title),            'icon' => 'pinterest',        ],        'email' => [            'label' => __('Share via Email', 'aqualuxe'),            'url' => 'mailto:?subject=' . urlencode($title) . '&body=' . urlencode($permalink),            'icon' => 'mail',        ],    ];        return apply_filters('aqualuxe_share_links', $share_links, $post->ID);}